export interface StyleCustomizationApiUpdateStyleCustomizationRequest {
    /**
     * Scope at which to apply the preferences. CLUSTER sets cluster-level defaults for all orgs. ORG applies to the authenticated user\\\&#39;s org.
     * Defaults to: &#39;ORG&#39;
     * @type string
     * @memberof StyleCustomizationApiupdateStyleCustomization
     */
    scope: string
    /**
     * Operation to perform. REPLACE (default) applies the provided fields and leaves omitted fields unchanged. RESET reverts fields listed in reset_options to defaults.
     * Defaults to: &#39;REPLACE&#39;
     * @type string
     * @memberof StyleCustomizationApiupdateStyleCustomization
     */
    operation?: string
    /**
     * Fields to reset when operation is RESET. Specify style fields and visualization areas to revert to defaults.
     * Defaults to: undefined
     * @type StyleResetOptionsInput
     * @memberof StyleCustomizationApiupdateStyleCustomization
     */
    resetOptions?: StyleResetOptionsInput
    /**
     * Navigation panel color. Provide theme and, when theme is CUSTOM, also provide base_color.
     * Defaults to: undefined
     * @type NavigationPanelInput
     * @memberof StyleCustomizationApiupdateStyleCustomization
     */
    navigationPanel?: NavigationPanelInput
    /**
     * Chart color palette. When provided with operation REPLACE, exactly 8 color entries must be specified in colors.
     * Defaults to: undefined
     * @type StyleColorPaletteInput
     * @memberof StyleCustomizationApiupdateStyleCustomization
     */
    chartColorPalette?: StyleColorPaletteInput
    /**
     * Custom footer text for the embedded application. An empty string clears the footer.
     * Defaults to: undefined
     * @type string
     * @memberof StyleCustomizationApiupdateStyleCustomization
     */
    embeddedFooterText?: string
    /**
     * Font assignments per visualization area. Provide only the areas to update; omitted areas remain unchanged.
     * Defaults to: undefined
     * @type VisualizationFontsInput
     * @memberof StyleCustomizationApiupdateStyleCustomization
     */
    visualizationFonts?: VisualizationFontsInput
    /**
     * Binary image for the DEFAULT logo slot (square app icon and favicon; recommended 140x140 px). Accepted formats: PNG, JPG.
     * Defaults to: undefined
     * @type HttpFile
     * @memberof StyleCustomizationApiupdateStyleCustomization
     */
    defaultLogo?: HttpFile
    /**
     * Binary image for the WIDE logo slot (horizontal top nav bar logo; recommended 230x45 px). Accepted formats: PNG, JPG.
     * Defaults to: undefined
     * @type HttpFile
     * @memberof StyleCustomizationApiupdateStyleCustomization
     */
    wideLogo?: HttpFile
}

